${SEP}??!${DBG2:-ya!112${ESC}${SEP}prp${ESC}${SEP}p FAIL ex.c:0:m1${ESC}${SEP}pr${INTR}${QF2}}${SEP}${LB}
${SEP}'2i static void *ec_map(char *loc, char *cmd, char *arg)
{
	char **map = cmd[0] == 'n' ? nmaps[xkmap] : imaps[xkmap];
	int unmap = !!strchr(cmd, '!');
	if (!arg[0]) {
		char msg[64];
		for (int i = 0; i < 256; i++) {
			if (map[i]) {
				snprintf(msg, sizeof(msg), \"%c\\t%s\", i, map[i]);
				ex_print(msg, msg_ft)
			}
		}
		return NULL;
	}
	int c = (unsigned char)arg[0];
	if (unmap) {
		free(map[c]);
		map[c] = NULL;
	} else {
		if (!arg[1])
			return \"missing argument\";
		free(map[c]);
		map[c] = uc_dup(arg + 1);
	}
	return NULL;
}

int map_read(int mode, int winch)
{
	int c = term_read(winch);
	if (ibuf_cnt != 1)
		return c;
	char **map = mode ? imaps[xkmap] : nmaps[xkmap];
	if (c > 0 && c < 256 && map[c]) {
		term_push(map[c], strlen(map[c]));
		return term_read(winch);
	}
	return c;
}

